const crypto = require('crypto');

// --- Password Hashing using scrypt (built-in to Node.js, no external dependencies) ---

const SCRYPT_KEYLEN = 64;
const SCRYPT_COST = 16384;   // N parameter (CPU/memory cost)
const SCRYPT_BLOCK_SIZE = 8; // r parameter
const SCRYPT_PARALLELIZATION = 1; // p parameter
const SALT_LENGTH = 32;

async function hashPassword(plainTextPassword) {
  return new Promise((resolve, reject) => {
    const salt = crypto.randomBytes(SALT_LENGTH);
    const options = {
      N: SCRYPT_COST,
      r: SCRYPT_BLOCK_SIZE,
      p: SCRYPT_PARALLELIZATION,
      maxmem: 128 * SCRYPT_COST * SCRYPT_BLOCK_SIZE * 2
    };

    crypto.scrypt(plainTextPassword, salt, SCRYPT_KEYLEN, options, (err, derivedKey) => {
      if (err) return reject(err);

      // Store parameters alongside the hash so we can verify later and upgrade params
      const params = `${SCRYPT_COST}:${SCRYPT_BLOCK_SIZE}:${SCRYPT_PARALLELIZATION}`;
      const hashString = `scrypt$${params}$${salt.toString('hex')}$${derivedKey.toString('hex')}`;
      resolve(hashString);
    });
  });
}

async function verifyPassword(plainTextPassword, storedHash) {
  return new Promise((resolve, reject) => {
    const parts = storedHash.split('$');
    if (parts.length !== 4 || parts[0] !== 'scrypt') {
      return resolve(false);
    }

    const [, paramStr, saltHex, keyHex] = parts;
    const [N, r, p] = paramStr.split(':').map(Number);
    const salt = Buffer.from(saltHex, 'hex');
    const storedKey = Buffer.from(keyHex, 'hex');

    const options = {
      N,
      r,
      p,
      maxmem: 128 * N * r * 2
    };

    crypto.scrypt(plainTextPassword, salt, storedKey.length, options, (err, derivedKey) => {
      if (err) return reject(err);
      // Constant-time comparison to prevent timing attacks
      resolve(crypto.timingSafeEqual(derivedKey, storedKey));
    });
  });
}

// --- Secure Session Token Generation ---

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Simple in-memory session store (use Redis or a database in production)
const sessions = new Map();
const SESSION_TTL_MS = 30 * 60 * 1000; // 30 minutes

function createSession(userId) {
  const token = generateSessionToken();
  const expiresAt = Date.now() + SESSION_TTL_MS;
  sessions.set(token, { userId, expiresAt });
  return { token, expiresAt };
}

function validateSession(token) {
  const session = sessions.get(token);
  if (!session) return null;
  if (Date.now() > session.expiresAt) {
    sessions.delete(token);
    return null;
  }
  return session;
}

function destroySession(token) {
  sessions.delete(token);
}

// --- Rate Limiting for Authentication ---

const loginAttempts = new Map(); // key: identifier (IP or username), value: { count, windowStart }
const RATE_LIMIT_WINDOW_MS = 15 * 60 * 1000; // 15 minutes
const RATE_LIMIT_MAX_ATTEMPTS = 10;

function isRateLimited(identifier) {
  const now = Date.now();
  const record = loginAttempts.get(identifier);

  if (!record || (now - record.windowStart) > RATE_LIMIT_WINDOW_MS) {
    loginAttempts.set(identifier, { count: 1, windowStart: now });
    return false;
  }

  record.count += 1;
  if (record.count > RATE_LIMIT_MAX_ATTEMPTS) {
    return true;
  }
  return false;
}

function resetRateLimit(identifier) {
  loginAttempts.delete(identifier);
}

