const AUTH_FAILURE_MESSAGE = 'Invalid credentials.';

async function registerUser(username, password) {
  if (!username || !password) {
    return { success: false, message: 'Username and password are required.' };
  }

  if (password.length < 8) {
    return { success: false, message: 'Password must be at least 8 characters.' };
  }

  if (users.has(username)) {
    // Generic message to avoid revealing whether the username exists
    return { success: false, message: 'Registration failed. Please try a different username.' };
  }

  const hashedPassword = await hashPassword(password);
  users.set(username, { username, hashedPassword, createdAt: new Date().toISOString() });

  return { success: true, message: 'User registered successfully.' };
}

async function loginUser(username, password, clientIdentifier) {
  // Check rate limit using client identifier (e.g., IP address)
  if (isRateLimited(clientIdentifier)) {
    return { success: false, message: 'Too many login attempts. Please try again later.' };
  }

  if (!username || !password) {
    return { success: false, message: AUTH_FAILURE_MESSAGE };
  }

  const user = users.get(username);
  if (!user) {
    // Still run a dummy hash to prevent timing-based user enumeration
    await hashPassword('dummy-password-to-equalize-timing');
    return { success: false, message: AUTH_FAILURE_MESSAGE };
  }

  const isValid = await verifyPassword(password, user.hashedPassword);
  if (!isValid) {
    return { success: false, message: AUTH_FAILURE_MESSAGE };
  }

  // Successful login — reset rate limit and create session
  resetRateLimit(clientIdentifier);
  const session = createSession(username);

  return {
    success: true,
    message: 'Login successful.',
    token: session.token,
    expiresAt: new Date(session.expiresAt).toISOString()
  };
}

